import{_ as a,C as d,o as n,c as s,j as t,a as i,E as l,ag as o}from"./chunks/framework.CAXxHpAX.js";const f="/parallel_faser.png",v=JSON.parse('{"title":"Procesguide — Redundante datacentre med HCI-platform","description":"","frontmatter":{"title":"Procesguide — Redundante datacentre med HCI-platform"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),m={name:"index.md"};function k(g,e,p,h,u,c){const r=d("PersonaFilter");return n(),s("div",null,[e[0]||(e[0]=t("h1",{id:"etablering-af-redundante-datacentre-med-hci-baseret-platform",tabindex:"-1"},[i("Etablering af redundante datacentre med HCI-baseret platform "),t("a",{class:"header-anchor",href:"#etablering-af-redundante-datacentre-med-hci-baseret-platform","aria-label":'Permalink to "Etablering af redundante datacentre med HCI-baseret platform"'},"​")],-1)),e[1]||(e[1]=t("p",null,[t("strong",null,"Overordnet procesguide for den fælles kommunale infrastruktur")],-1)),l(r),e[2]||(e[2]=o('<h2 id="sammenfatning" tabindex="-1">Sammenfatning <a class="header-anchor" href="#sammenfatning" aria-label="Permalink to &quot;Sammenfatning&quot;">​</a></h2><p>Dette dokument beskriver de centrale faser og principper for etablering af den logiske infrastruktur i redundante datacentre med en hyperkonvergent infrastruktur (HCI) som fundament for VM-baserede workloads. Processen er designet til at understøtte den kommende konsolidering af de 98 danske kommuners IT-infrastruktur ind i 5 fælles driftsenheder.</p><p>Det forventes, at de deltagende kommuner kommer fra vidt forskellige teknologiske udgangspunkter. Denne guide er derfor formuleret på et principniveau og er bevidst leverandør- og platformuafhængig. Formålet er at sikre, at de 5 driftsenheder etablerer en ensartet, redundant og skalerbar platform, der kan håndtere multi-tenant-drift med den driftsstabilitet, sikkerhed og automatiseringsgrad, som scoringsmodellen i konsolideringsparathedsanalysen beskriver som målbilledet (Niveau A).</p><p>Det forudsættes, at alle fysiske aspekter af datacenter-etableringen — herunder site-valg, strømforsyning, køling, fysisk sikkerhed og konnektivitet — er adresseret og på plads. Denne guide fokuserer på den logiske platform: fra netværksarkitektur og HCI-fundament til idriftsættelse af den første tenant, og er struktureret i 10 faser med tilhørende leverancer og opmærksomhedspunkter.</p><h2 id="parallelle-implementeringsfaser" tabindex="-1">Parallelle implementeringsfaser <a class="header-anchor" href="#parallelle-implementeringsfaser" aria-label="Permalink to &quot;Parallelle implementeringsfaser&quot;">​</a></h2><p>Nedenstående oversigt viser, hvordan de 10 faser kan paralleliseres. Den kritiske sti (Fase 1 → 2 → 3 → 9 → 10) er sekventiel, mens faserne for sikkerhed, standarder, governance og automatisering kan påbegyndes fra dag ét og køre parallelt med infrastrukturetableringen.</p><p><img src="'+f+'" alt="Parallelisering af de 10 faser"></p><p><strong>Kritisk sti:</strong> Fase 1 → 2 → 3 → 9 → 10 (infrastruktur-sekvensen). Faserne 4, 5, 6, 7 og 8 kan køre parallelt med den kritiske sti og skal blot være afsluttet inden Fase 9 påbegyndes.</p><h2 id="faseoversigt" tabindex="-1">Faseoversigt <a class="header-anchor" href="#faseoversigt" aria-label="Permalink to &quot;Faseoversigt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fase</th><th>Område</th><th>Sti</th><th>Personas</th></tr></thead><tbody><tr><td><a href="/faser/01-netvaerk.html">Fase 1</a></td><td>Netværksarkitektur &amp; backbone</td><td>🔴 Kritisk</td><td>Arkitekt, Driftsleder</td></tr><tr><td><a href="/faser/02-hci.html">Fase 2</a></td><td>HCI-platform — compute &amp; storage</td><td>🔴 Kritisk</td><td>Arkitekt, Driftsleder</td></tr><tr><td><a href="/faser/03-storage.html">Fase 3</a></td><td>Storage-tiering, replikering &amp; backup</td><td>🔴 Kritisk</td><td>Arkitekt, Driftsleder</td></tr><tr><td><a href="/faser/04-mikrosegmentering.html">Fase 4</a></td><td>Mikrosegmentering &amp; sikkerhed</td><td>🔵 Parallel</td><td>Arkitekt, Sikkerhed</td></tr><tr><td><a href="/faser/05-iam.html">Fase 5</a></td><td>Identitets- &amp; adgangsstyring</td><td>🔵 Parallel</td><td>Sikkerhed, IT-leder</td></tr><tr><td><a href="/faser/06-iac.html">Fase 6</a></td><td>IaC &amp; automatisering</td><td>🔵 Parallel</td><td>Arkitekt, Driftsleder</td></tr><tr><td><a href="/faser/07-standardisering.html">Fase 7</a></td><td>Standardisering, labelling &amp; CMDB</td><td>🔵 Parallel</td><td>Driftsleder, IT-leder</td></tr><tr><td><a href="/faser/08-governance.html">Fase 8</a></td><td>Governance &amp; SLA-framework</td><td>🔵 Parallel</td><td>IT-leder</td></tr><tr><td><a href="/faser/09-dr-test.html">Fase 9</a></td><td>DR-test, validering &amp; hærdning</td><td>🔴 Kritisk</td><td>Alle</td></tr><tr><td><a href="/faser/10-onboarding.html">Fase 10</a></td><td>Onboarding af første tenant</td><td>🔴 Kritisk</td><td>Alle</td></tr></tbody></table>',10))])}const P=a(m,[["render",k]]);export{v as __pageData,P as default};
